import { HfInference } from "@huggingface/inference";

const _rawKey = import.meta.env.VITE_HUGGINGFACE_API_KEY || '';
const HF_API_KEY = _rawKey.replace(/^["']|["']$/g, '').trim();

const hf = HF_API_KEY && HF_API_KEY !== 'YOUR_HF_TOKEN' ? new HfInference(HF_API_KEY) : null;

import type { WeatherData } from './api';

export interface AIInsight {
    summary: string;
    clothing: string;
    activity: string;
    heads_up: string;
}

export const generateWeatherInsight = async (weather: WeatherData): Promise<AIInsight | string> => {
    if (!hf) {
        return "🤖 AI Offline: A chave da Hugging Face API não foi encontrada no arquivo .env.";
    }

    try {
        const prompt = `You are a specialized AI weather assistant. Analyze the weather data and return ONLY a valid JSON object without any extra text or markdown.
Data: Location: ${weather.name}, Temp: ${Math.round(weather.main.temp)}°C, Feels like: ${Math.round(weather.main.feels_like)}°C, Humidity: ${weather.main.humidity}%, Wind: ${weather.wind.speed.toFixed(1)}m/s, Description: ${weather.weather[0].description}.
CRITICAL INSTRUCTION: The "heads_up" field is MANDATORY. If there is bad weather, provide a safety warning. If the weather is good, provide a helpful "heads-up" (e.g., "Drink plenty of water", "Don't forget your sunglasses!", "Perfect condition for a walk"). NEVER leave it empty.
Return EXACTLY this JSON format:
{
  "summary": "Greeting and 1 sentence overall summary",
  "clothing": "Short recommendation on what to wear",
  "activity": "One suggested activity or what to avoid",
  "heads_up": "MANDATORY safety warning or helpful heads-up based on weather."
}`;

        const out = await hf.chatCompletion({
            model: "Qwen/Qwen2.5-72B-Instruct",
            messages: [
                { role: "system", content: "You are a specialized JSON-only AI. Output strictly valid JSON." },
                { role: "user", content: prompt }
            ],
            max_tokens: 200,
            temperature: 0.5,
        });

        if (out.choices && out.choices.length > 0 && out.choices[0].message?.content) {
            const content = out.choices[0].message.content.trim();
            const jsonMatch = content.match(/\{[\s\S]*\}/);
            if (jsonMatch) {
                return JSON.parse(jsonMatch[0]) as AIInsight;
            }
            return content; // Fallback
        }

        return "🤖 AI Offline: A Hugging Face não devolveu um texto legível.";
    } catch (err: any) {
        console.warn("Hugging Face API falhou:", err);
        return `🤖 AI Offline: Erro na Hugging Face. (${err.message})`;
    }
};

import axios from 'axios';

const OPENWEATHER_API_KEY = import.meta.env.VITE_OPENWEATHER_API_KEY;
const BASE_URL = 'https://api.openweathermap.org/data/2.5';

export interface WeatherData {
    name: string;
    sys: { country: string };
    main: { temp: number; feels_like: number; humidity: number; pressure: number; temp_min: number; temp_max: number };
    weather: [{ main: string; description: string; icon: string }];
    wind: { speed: number };
    coord: { lat: number; lon: number };
}

export interface ForecastData {
    city: { name: string; coord: { lat: number; lon: number } };
    list: Array<{
        dt: number;
        main: { temp: number; temp_min: number; temp_max: number; humidity: number };
        weather: [{ main: string; description: string; icon: string }];
        wind: { speed: number };
        dt_txt: string;
        pop: number;
    }>;
}

// No mock data - errors should be handled by the UI

export const weatherApi = {
    async getCurrentWeather(query: string | { lat: number; lon: number }): Promise<WeatherData> {
        const params: any = { appid: OPENWEATHER_API_KEY, units: 'metric' };
        if (typeof query === 'string') {
            params.q = query;
        } else {
            params.lat = query.lat;
            params.lon = query.lon;
        }
        const response = await axios.get(`${BASE_URL}/weather`, { params });
        return response.data;
    },

    async getForecast(query: string | { lat: number; lon: number }): Promise<ForecastData> {
        const params: any = { appid: OPENWEATHER_API_KEY, units: 'metric' };
        if (typeof query === 'string') {
            params.q = query;
        } else {
            params.lat = query.lat;
            params.lon = query.lon;
        }
        const response = await axios.get(`${BASE_URL}/forecast`, { params });
        return response.data;
    }
};

import axios from 'axios';
import type { WeatherData } from './api';

const STRAPI_URL = 'http://localhost:1337/api';

export interface WeatherRecord {
    id: number;
    documentId: string;
    location: string;
    latitude: number;
    longitude: number;
    startDate: string;
    endDate: string;
    weatherData: any;
    createdAt: string;
}

export const strapiApi = {
    // CREATE
    async saveRecord(location: string, data: WeatherData) {
        try {
            const payload = {
                data: {
                    location,
                    latitude: data.coord.lat,
                    longitude: data.coord.lon,
                    startDate: new Date().toISOString(),
                    endDate: new Date(Date.now() + 5 * 24 * 60 * 60 * 1000).toISOString(),
                    weatherData: data,
                }
            };
            const res = await axios.post(`${STRAPI_URL}/weather-records`, payload);
            return res.data;
        } catch (e) {
            console.error('Failed to save to Strapi:', e);
        }
    },

    // READ
    async getRecords(): Promise<WeatherRecord[]> {
        try {
            const res = await axios.get(`${STRAPI_URL}/weather-records?sort=createdAt:desc`);
            return res.data.data;
        } catch (e) {
            console.error('Failed to fetch from Strapi:', e);
            return [];
        }
    },

    // UPDATE (To meet the assessment criteria of allowing users to update records)
    async updateRecordLocation(documentId: string, newLocationName: string) {
        try {
            const payload = { data: { location: newLocationName } };
            const res = await axios.put(`${STRAPI_URL}/weather-records/${documentId}`, payload);
            return res.data;
        } catch (e) {
            console.error('Failed to update Strapi:', e);
        }
    },

    // DELETE
    async deleteRecord(documentId: string) {
        try {
            const res = await axios.delete(`${STRAPI_URL}/weather-records/${documentId}`);
            return res.data;
        } catch (e) {
            console.error('Failed to delete from Strapi:', e);
        }
    }
};
